    public List<List<String>> getPercentageOutputLines(String tab) {
        Map<String, Map<String, String>> meetStandard = new HashMap<>();
        Map<String, Map<String, String>> underStandard = new HashMap<>();
        Map<String, BigDecimal> _standardPercentage = this.standardPercentage;
        List<String> skuSuffixList = new ArrayList<>();
        List<List<String>> outputLines = new ArrayList<>();
        
        this.comparePercentage(tab, meetStandard, underStandard, skuSuffixList);
        
        Collections.sort(skuSuffixList);
        
        for (int i = 0; i < skuSuffixList.size(); i++) {
            String skuSuffix = skuSuffixList.get(i);
            List<String> row1 = new ArrayList<>();
            List<String> row2 = new ArrayList<>();
            BigDecimal standardPct = _standardPercentage.get(skuSuffix);
            String outOfRange = ">" + standardPct.add(new BigDecimal("0.02")).toString() + ", <" + standardPct.subtract(new BigDecimal("0.02")).toString();
            
            row1.add(skuSuffix);
            row1.add(standardPct.toString());
            if (meetStandard.get(skuSuffix) != null) {
                row1.add("" + meetStandard.get(skuSuffix).size());
            }
            else {
                row1.add("0");
            }
            outputLines.add(row1);
            
            row2.add("");
            row2.add(outOfRange);
            if (underStandard.get(skuSuffix) != null) {
                row2.add("" + underStandard.get(skuSuffix).size());
            }
            else {
                row2.add("0");
            }
            outputLines.add(row2);
            
            outputLines.add(Arrays.asList("", "", ""));
            
            Map<String, String> skuToPercentage = underStandard.get(skuSuffix);
            
            if (skuToPercentage != null) {
                int entryNum = 0;
                for (Map.Entry<String, String> e : skuToPercentage.entrySet()) {
                    List<String> row = new ArrayList<>();
                    String sku = e.getKey();
                    String percentage = e.getValue();
                    
                    row.add("" + (++entryNum));
                    row.add(sku);
                    row.add(percentage);
                    outputLines.add(row);
                }
                outputLines.add(Arrays.asList("", "", ""));
            }
            
            outputLines.add(Arrays.asList("", "", ""));
            
        }
        
        return outputLines;
    }
    
    public void comparePercentage(String tab, Map<String, Map<String, String>> meetStandard, Map<String, Map<String, String>> underStandard, List<String> skuSuffixList) {
        
        for (Map.Entry<String, Map<String, BigDecimal>> e : this.skuSuffixMap.entrySet()) {
            String skuSuffix = e.getKey();
            Map<String, BigDecimal> skuMap = e.getValue();
            BigDecimal stdPercentage = standardPercentage.get(skuSuffix);
            //System.out.println(skuSuffix+", "+stdPercentage);
            if (stdPercentage == null) continue;
            
            skuSuffixList.add(skuSuffix);
            
            for (Map.Entry<String, BigDecimal> e2 : skuMap.entrySet()) {
                String sku = e2.getKey();
                BigDecimal percentage = e2.getValue();
                String percentageStr = percentage.setScale(2, ROUND_HALF_UP).toString();
                
                if (percentage.subtract(stdPercentage).abs().compareTo(new BigDecimal("0.02")) == 1) { //greater than 0.02
                    Map<String, String> skuMapUnderStd = underStandard.get(skuSuffix);
                    if (skuMapUnderStd == null) {
                        skuMapUnderStd = new TreeMap<>();
                        underStandard.put(skuSuffix, skuMapUnderStd);
                    }
                    skuMapUnderStd.put(sku, percentageStr);
                }
                else {
                    Map<String, String> skuMapMeetStd = meetStandard.get(skuSuffix);
                    if (skuMapMeetStd == null) {
                        skuMapMeetStd = new TreeMap<>();
                        meetStandard.put(skuSuffix, skuMapMeetStd);
                    }
                    skuMapMeetStd.put(sku, percentageStr);
                }
            }
        }
    }
    
